--- a/llvm/lib/Transforms/Utils/ScalarEvolutionExpander.cpp
+++ b/llvm/lib/Transforms/Utils/ScalarEvolutionExpander.cpp
@@ -2263,7 +2263,22 @@ Value *SCEVExpander::fixupLCSSAFormFor(Value *V) {
     PN->eraseFromParent();
   }

-  return User->getOperand(0);
+  // After creating LCSSA PHIs, find the value that dominates the insertion
+  // point. If there is a PHI in the insertion block, use it; otherwise,
+  // search for a dominating PHI in the predecessor blocks.
+  BasicBlock *InsertBB = InsertPt->getParent();
+  for (PHINode *PN : InsertedPHIs) {
+    if (PN->getParent() == InsertBB)
+      return PN;
+  }
+  // If no PHI in the insertion block, check if the original value dominates
+  // the insertion point.
+  if (SE.DT.dominates(DefI, InsertPt))
+    return DefI;
+  // Otherwise, we need to create a PHI in InsertBB to merge values from
+  // predecessors. For now, return DefI and hope for the best (this should
+  // not happen because formLCSSAForInstructions should have handled it).
+  return DefI;
 }

