     PN->eraseFromParent();
   }

-  return User->getOperand(0);
+  // Return the LCSSA PHI that dominates the original insertion point, if any.
+  // Otherwise, return the original value.
+  BasicBlock *InsertBB = InsertPt->getParent();
+  for (PHINode *PN : InsertedPHIs) {
+    if (SE.DT.dominates(PN, InsertPt))
+      return PN;
+  }
+  // If no dominating PHI, maybe the original value dominates.
+  if (SE.DT.dominates(DefI, InsertPt))
+    return DefI;
+  // Otherwise, we have to return DefI and hope for the best.
+  return DefI;
 }

