diff --git a/llvm/lib/Transforms/Utils/ScalarEvolutionExpander.cpp b/llvm/lib/Transforms/Utils/ScalarEvolutionExpander.cpp
index 0927a3015818..9ac0f2e67c6a 100644
--- a/llvm/lib/Transforms/Utils/ScalarEvolutionExpander.cpp
+++ b/llvm/lib/Transforms/Utils/ScalarEvolutionExpander.cpp
@@ -2263,7 +2263,21 @@ Value *SCEVExpander::fixupLCSSAFormFor(Value *V) {
     PN->eraseFromParent();
   }

-  return User->getOperand(0);
+  // Use SSAUpdater to get the value at the insertion point.
+  SmallVector<PHINode *, 4> InsertedPHIsCopy(InsertedPHIs.begin(), InsertedPHIs.end());
+  SSAUpdater SSA;
+  SSA.Initialize(DefI->getType(), DefI->getName());
+  // Add available values from all inserted PHIs.
+  for (PHINode *PN : InsertedPHIsCopy) {
+    SSA.AddAvailableValue(PN->getParent(), PN);
+  }
+  // Also add the original value if it dominates its own block.
+  if (SE.DT.dominates(DefI, DefI->getParent()))
+    SSA.AddAvailableValue(DefI->getParent(), DefI);
+  // Get the value at the insertion point.
+  Value *Result = SSA.GetValueAtEndOfBlock(InsertPt->getParent());
+  rememberInstruction(cast<Instruction>(Result));
+  return Result;
 }

